#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+5;
int n,m,c[maxn],a[maxn],g;
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=0;i<n;i++){
		cin>>c[i];
		g=max(g,c[i]);
	}
	for(int i=0;i<m;i++){
		cin>>a[i];
	}
	if(n==1){
		for(int i=0;i<m;i++){
			c[0]+=a[i];
		}
		cout<<c[0];
		return 0;
	}
	for(int i=0;i<m;i++){
        if(a[i]>=0){
            g+=a[i];
        }
    }
    cout<<g;
	return 0;
}
